// Format the patient data for clean JSON response
const patients = items.map(item => ({
  id: item.json.id,
  salesforceId: item.json.salesforce_id,
  firstName: item.json.first_name,
  lastName: item.json.last_name,
  fullName: `${item.json.first_name} ${item.json.last_name}`,
  email: item.json.email,
  phone: item.json.phone,
  procedureInterest: item.json.procedure_interest,
  lastVisitDate: item.json.last_visit_date,
  consultationNotes: item.json.consultation_notes,
  callRecordingSummary: item.json.call_recording_summary,
  engagementScore: item.json.engagement_score,
  preferredChannel: item.json.preferred_channel,
  createdAt: item.json.created_at
}));

return [{
  json: {
    success: true,
    count: patients.length,
    patients: patients,
    filters: {
      procedureInterest: $('Webhook Trigger').item.json.query?.procedure_interest || null,
      minEngagementScore: $('Webhook Trigger').item.json.query?.min_engagement_score ? parseInt($('Webhook Trigger').item.json.query.min_engagement_score) : null,
      preferredChannel: $('Webhook Trigger').item.json.query?.preferred_channel || null
    },
    timestamp: new Date().toISOString()
  }
}];

// Format single patient detail response
if (items.length === 0) {
  return [{
    json: {
      success: false,
      error: 'Patient not found',
      patientId: $('Webhook Single Patient').item.json.params.id,
      timestamp: new Date().toISOString()
    }
  }];
}

const patient = items[0].json;

return [{
  json: {
    success: true,
    patient: {
      id: patient.id,
      salesforceId: patient.salesforce_id,
      firstName: patient.first_name,
      lastName: patient.last_name,
      fullName: `${patient.first_name} ${patient.last_name}`,
      email: patient.email,
      phone: patient.phone,
      procedureInterest: patient.procedure_interest,
      lastVisitDate: patient.last_visit_date,
      consultationNotes: patient.consultation_notes,
      callRecordingSummary: patient.call_recording_summary,
      engagementScore: patient.engagement_score,
      preferredChannel: patient.preferred_channel,
      createdAt: patient.created_at
    },
    timestamp: new Date().toISOString()
  }
}];
